const input = $input.first().json;

const msg = input.message && typeof input.message === 'object'
  ? input.message
  : {};

const from = msg.from || {};
const chat = msg.chat || {};

const text = String(
  input.search_query ||
  input.raw_text ||
  input.text ||
  input.content ||
  (typeof input.message === 'string' ? input.message : '') ||
  msg.text ||
  msg.caption ||
  ''
).trim();

const userId =
  input.user_id ||
  from.id ||
  chat.id ||
  null;

const chatId =
  input.chat_id ||
  chat.id ||
  from.id ||
  userId ||
  null;

return [
  {
    json: {
      ...input,

      user_id: userId,
      chat_id: chatId,

      search_query: text,
      is_empty_search_query: text.length === 0
    }
  }
];

const input = $input.first().json;

return [
  {
    json: {
      chat_id: input.chat_id,
      user_id: input.user_id,
      ok: false,
      search_query: input.search_query || '',
      text: `I couldn't read the search query. Please send it as text, or try another voice message.`,
      inline_keyboard: [
        [
          {
            text: '🔎 Search again',
            callback_data: 'action:search'
          }
        ],
        [
          {
            text: '❌ Cancel',
            callback_data: 'action:cancel_search'
          }
        ]
      ]
    }
  }
];

const items = $input.all();

let input = {};

try {
  input = $('Prepare search query input').first().json || {};
} catch (e) {
  input = {};
}

const realResults = items.filter(item => {
  const r = item.json || {};
  return r.message_id || r.id;
});

const chatId =
  input.chat_id ||
  realResults[0]?.json?.chat_id ||
  null;

const userId =
  input.user_id ||
  realResults[0]?.json?.user_id ||
  null;

const searchQuery =
  input.search_query ||
  realResults[0]?.json?.search_query ||
  '';

if (realResults.length === 0) {
  return [
    {
      json: {
        no_results: true,
        user_id: userId,
        chat_id: chatId,
        search_query: searchQuery,
        total_results: 0
      }
    }
  ];
}

return realResults.map((item, index) => {
  const r = item.json || {};

  return {
    json: {
      id: r.id || r.message_id,
      message_id: r.message_id || r.id,

      user_id: r.user_id || userId,
      chat_id: r.chat_id || chatId,

      topic_id: r.topic_id || null,
      topic_title: r.topic_title || null,

      result_number: Number(r.result_number || index + 1),
      result_position: Number(r.result_number || index + 1),
      total_results: Number(r.total_results || realResults.length),
      relevance_score: r.relevance_score !== undefined && r.relevance_score !== null
        ? Number(r.relevance_score)
        : null,

      search_query: r.search_query || searchQuery,

      message_uuid: r.message_uuid || null,
      content: r.content || null,
      created_at: r.created_at || null,
      message_type: r.message_type || 'text',

      file_id: r.file_id || null,
      file_unique_id: r.file_unique_id || null,
      file_name: r.file_name || null,
      mime_type: r.mime_type || null,
      caption: r.caption || null,
      telegram_file_path: r.telegram_file_path || null,
      file_url: r.file_url || null,

      latitude: r.latitude || null,
      longitude: r.longitude || null,
      location_title: r.location_title || null,
      location_address: r.location_address || null,
      maps_url: r.maps_url || null,

      ai_summary: r.ai_summary || null,
      ai_category: r.ai_category || null,
      ai_language: r.ai_language || null,
      ai_keywords: r.ai_keywords || null,
      ai_content: r.ai_content || null,

      result_action: r.result_action || 'text',
      display_text:
        r.display_text ||
        r.file_name ||
        r.caption ||
        r.content ||
        r.location_title ||
        r.location_address ||
        r.maps_url ||
        r.ai_summary ||
        'Message'
    }
  };
});
